import openpyxl

wb = openpyxl.load_workbook('input.xlsx')
ws = wb['Sheet1']

# Read all data
rows_data = []
for row in ws.iter_rows(min_row=1, max_row=ws.max_row, max_col=5):
    row_vals = []
    for cell in row:
        row_vals.append({
            'value': cell.value,
            'number_format': cell.number_format
        })
    rows_data.append(row_vals)

# Step 1: Calculate sum of D where E == 0 (skip header)
sum_d_zero = 0
for i, r in enumerate(rows_data):
    if i == 0:
        continue
    if r[4]['value'] == 0:
        val = r[3]['value']
        if isinstance(val, (int, float)):
            sum_d_zero += val

sum_d_zero = round(sum_d_zero, 2)
print(f"Sum of D where E=0: {sum_d_zero}")

# Step 2: Find BR1 Sales row and set its D value to the sum
for i, r in enumerate(rows_data):
    c_val = r[2]['value']
    if isinstance(c_val, str) and 'BR1 Sales' in c_val:
        rows_data[i][3]['value'] = sum_d_zero
        break

# Step 3 & 4: Filter - keep header, BR1 Sales rows, non-zero E rows; remove blanks
kept_rows = []
for i, r in enumerate(rows_data):
    if i == 0:
        kept_rows.append(r)
        continue
    all_none = all(cell['value'] is None for cell in r)
    if all_none:
        continue
    c_val = r[2]['value']
    is_br1_sales = isinstance(c_val, str) and 'BR1 Sales' in c_val
    e_val = r[4]['value']
    if is_br1_sales:
        kept_rows.append(r)
    elif e_val == 0:
        continue
    else:
        kept_rows.append(r)

# Write output
wb2 = openpyxl.Workbook()
ws2 = wb2.active
ws2.title = 'Sheet1'

for row_idx, r in enumerate(kept_rows, start=1):
    for col_idx, cell_data in enumerate(r, start=1):
        cell = ws2.cell(row=row_idx, column=col_idx)
        cell.value = cell_data['value']
        if cell_data['number_format'] != 'General':
            cell.number_format = cell_data['number_format']

wb2.save('output.xlsx')
print(f"Saved output.xlsx with {len(kept_rows)} rows")
for r in kept_rows:
    print([c['value'] for c in r])
